  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// 运单本地快照表（V3 自有）\n// 从 V2 接口同步的运单只读快照，用于异常工单关联展示\nmodel OrderSnapshot {\n  id              String   @id @default(cuid())\n  v2OrderId       String   @unique // V2 系统的运单 ID\n  externalCode    String? // 外部单号\n  storeName       String? // 店铺名称\n  receiverName    String? // 收件人姓名\n  receiverPhone   String? // 收件人电话\n  receiverAddress String? // 收件人地址\n  amount          Float? // 运单金额\n  itemsJson       Json // 商品明细 JSON（快照）\n  syncedAt        DateTime @default(now()) // 同步时间\n  createdAt       DateTime @default(now())\n  updatedAt       DateTime @updatedAt\n\n  // 关联\n  exceptionTickets ExceptionTicket[]\n  scanRecords      ScanRecord[]\n\n  @@index([v2OrderId])\n  @@index([externalCode])\n  @@index([syncedAt])\n}\n\n// 接口同步日志表\nmodel SyncLog {\n  id             String   @id @default(cuid())\n  apiName        String // 接口名称\n  requestParams  Json // 请求参数摘要\n  responseStatus Int // HTTP 状态码\n  responseBody   String? // 响应内容（脱敏）\n  status         String // SUCCESS | FAILED | TIMEOUT\n  errorMessage   String? // 错误信息\n  duration       Int // 耗时（毫秒）\n  createdAt      DateTime @default(now())\n\n  @@index([apiName])\n  @@index([status])\n  @@index([createdAt])\n}\n\n// 扫描记录表（V3 自有）\nmodel ScanRecord {\n  id              String        @id @default(cuid())\n  scanId          String        @unique // 扫描 ID\n  orderSnapshotId String\n  orderSnapshot   OrderSnapshot @relation(fields: [orderSnapshotId], references: [id], onDelete: Restrict)\n\n  skuCode         String\n  skuName         String\n  scannedQuantity Int // 扫描数量\n  scanTime        DateTime @default(now())\n  operator        String // 操作人\n  deviceId        String? // 设备 ID\n\n  // 品控判定结果\n  qcResult      String // PASS | FAIL\n  qcRuleId      String? // 命中的品控规则 ID\n  qcRuleName    String? // 命中的品控规则名称\n  qcDescription String? // 品控异常描述\n\n  // 批次锁定状态\n  batchStatus String // NORMAL | QC_HOLD\n\n  // 关联工单（异常时非空）\n  ticketId String?\n  ticket   ExceptionTicket? @relation(fields: [ticketId], references: [id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n\n  @@index([orderSnapshotId])\n  @@index([skuCode])\n  @@index([scanTime])\n  @@index([ticketId])\n  @@index([batchStatus])\n}\n\n// 异常工单表\nmodel ExceptionTicket {\n  id              String        @id @default(cuid())\n  ticketNo        String        @unique // 工单编号\n  orderSnapshotId String\n  orderSnapshot   OrderSnapshot @relation(fields: [orderSnapshotId], references: [id], onDelete: Restrict)\n\n  // 异常分类\n  exceptionType String // QC | LOGISTICS\n  source        String // SCAN_QC | MANUAL_LOGISTICS\n  category      String // 异常子类型（破损/丢件/拒收等）\n  description   String // 详细描述\n\n  // 工单状态\n  status   String @default(\"PENDING\") // PENDING | LEVEL1_APPROVING | LEVEL2_APPROVING | EXECUTING | COMPLETED | REJECTED | CANCELLED\n  priority String @default(\"MEDIUM\") // LOW | MEDIUM | HIGH | URGENT\n\n  // 审批相关\n  currentApprovalLevel Int @default(1) // 当前审批层级 1 | 2\n  resubmitCount        Int @default(0) // 已重新提交次数\n  maxResubmitCount     Int @default(3) // 最大重新提交次数\n\n  // 操作人\n  submittedBy String // 上报人\n  submittedAt DateTime  @default(now())\n  completedAt DateTime? // 完成时间\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // 关联\n  scanRecords         ScanRecord[]\n  approvalRecords     ApprovalRecord[]\n  compensationRecords CompensationRecord[]\n\n  @@index([orderSnapshotId])\n  @@index([status])\n  @@index([exceptionType])\n  @@index([source])\n  @@index([submittedAt])\n}\n\n// 审批记录表\nmodel ApprovalRecord {\n  id       String          @id @default(cuid())\n  ticketId String\n  ticket   ExceptionTicket @relation(fields: [ticketId], references: [id], onDelete: Cascade)\n\n  approvalLevel Int // 审批层级 1 | 2\n  approverId    String // 审批人 ID\n  approverName  String // 审批人姓名\n  action        String // APPROVE | REJECT | ESCALATE | TRANSFER\n  comment       String // 审批意见\n\n  approvedAt DateTime // 审批时间\n  createdAt  DateTime @default(now())\n\n  @@index([ticketId])\n  @@index([approverId])\n  @@index([approvedAt])\n}\n\n// 赔付记录表\nmodel CompensationRecord {\n  id       String          @id @default(cuid())\n  ticketId String\n  ticket   ExceptionTicket @relation(fields: [ticketId], references: [id], onDelete: Cascade)\n\n  approvalRecordId String // 关联审批记录 ID\n  amount           Float // 赔付金额\n  direction        String // TO_CUSTOMER | FROM_SUPPLIER\n  status           String @default(\"PENDING\") // PENDING | PAID | RECOVERED | CANCELLED\n\n  reason        String // 赔付原因\n  paymentMethod String? // 支付方式\n  paidAt        DateTime? // 支付时间\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([ticketId])\n  @@index([approvalRecordId])\n  @@index([status])\n}\n\n// 库存记录表\nmodel InventoryRecord {\n  id          String @id @default(cuid())\n  skuCode     String\n  warehouseId String @default(\"default\")\n\n  quantityChange Int // 正数=增加，负数=减少\n  changeType     String // COMPENSATION_DEDUCT | COMPENSATION_ADD | RETURN_IN | RESHIP_DEDUCT | QC_RELEASE | QC_HOLD\n\n  ticketId         String?\n  approvalRecordId String?\n\n  operator String // 操作人\n  remark   String // 备注\n\n  createdAt DateTime @default(now())\n\n  @@index([skuCode])\n  @@index([warehouseId])\n  @@index([ticketId])\n  @@index([createdAt])\n}\n\n// 品控规则表（V3 自有）\nmodel QCRule {\n  id          String @id @default(cuid())\n  name        String // 规则名称\n  code        String @unique // 规则编码\n  description String // 规则描述\n\n  exceptionType    String // 异常类型\n  triggerCondition Json // 触发条件（JSON 配置）\n  // {\n  //   type: \"quantity_diff_percent\" | \"damage_level\" | \"spec_mismatch\" | \"label_error\" | \"batch_anomaly\",\n  //   threshold: number,\n  //   operator?: \">\" | \"<\" | \">=\" | \"<=\" | \"==\" | \"!=\"\n  // }\n\n  severity          String // LOW | MEDIUM | HIGH | CRITICAL\n  autoCreateTicket  Boolean @default(true) // 是否自动创建工单\n  autoApprovalLevel Int     @default(1) // 自动进入审批级别\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([exceptionType])\n  @@index([isActive])\n}\n\n// 系统配置表（用于存储分级审批金额阈值、超时时长等可配置参数）\nmodel SystemConfig {\n  id          String   @id @default(cuid())\n  configKey   String   @unique\n  configValue String\n  configType  String // NUMBER | STRING | JSON | BOOLEAN\n  description String?\n  category    String // APPROVAL | TIMEOUT | QC | NOTIFICATION\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@index([configKey])\n  @@index([category])\n}\n",
